import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is the marriage tax penalty?", a: "A marriage tax penalty happens when a couple owes more tax filing jointly than they would owe if each spouse filed as a single person." },
  { q: "What is the marriage tax bonus?", a: "A marriage tax bonus happens when joint filing produces a lower combined tax bill than two separate single returns." },
  { q: "Should you file taxes jointly or separately after marriage?", a: "Most couples file jointly, but separate filing can help in special cases involving student loans, deductions, or liability concerns." },
  { q: "How do tax brackets change when you get married?", a: "Married filing jointly brackets are generally wider than single brackets, but not always perfectly doubled at higher incomes." },
  { q: "What other tax benefits come with marriage?", a: "Marriage can affect deductions, credits, IRA rules, estate planning, and health coverage, depending on your income and situation." },
];

const money = (v: number, d = 0) => formatCurrencyValue(v, { maximumFractionDigits: d });
const SINGLE = [[0, 11600, .10], [11600, 47150, .12], [47150, 100525, .22], [100525, 191950, .24], [191950, 243725, .32], [243725, 609350, .35], [609350, Infinity, .37]];
const JOINT = [[0, 23200, .10], [23200, 94300, .12], [94300, 201050, .22], [201050, 383900, .24], [383900, 487450, .32], [487450, 731200, .35], [731200, Infinity, .37]];
function tax(income: number, status: "single" | "joint") {
  const taxable = Math.max(0, income - (status === "single" ? 14600 : 29200));
  return (status === "single" ? SINGLE : JOINT).reduce((sum, [min, max, rate]) => taxable > min ? sum + (Math.min(taxable, max) - min) * rate : sum, 0);
}
function scenario(a: number, b: number) {
  const singleTax = tax(a, "single") + tax(b, "single");
  const jointTax = tax(a + b, "joint");
  return { a, b, singleTax, jointTax, bonus: singleTax - jointTax };
}

export default function MarriageTaxCalculator() {
  useCurrencyVersion();
  const [spouse1, setSpouse1] = useState(80000);
  const [spouse2, setSpouse2] = useState(50000);
  const [status, setStatus] = useState("Married filing jointly");
  const result = scenario(spouse1, spouse2);
  const rows = [[50000, 50000], [75000, 25000], [100000, 50000], [150000, 0], [150000, 150000], [250000, 50000]].map(([a, b]) => scenario(a, b));
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
  return (
    <>
      <SEOHead title="Free Marriage Tax Calculator Online - Calculate Your Marriage Tax Bonus or Penalty Instantly | CalcHive" description="Free online marriage tax calculator. Calculate whether you pay more or less tax after marriage by comparing single vs joint filing tax liability instantly. 100% free, no signup required." canonical="/marriage-tax-calculator" keywords="free marriage tax calculator, marriage penalty calculator free online, marriage bonus calculator free, married filing jointly vs single calculator free, marriage tax impact calculator free" category="Financial Calculators" breadcrumbName="Free Marriage Tax Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Marriage Tax Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Compare single tax liability against married filing jointly to estimate a marriage tax bonus or penalty.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Spouse 1 income</label><input type="number" value={spouse1} onChange={(e) => setSpouse1(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Spouse 2 income</label><input type="number" value={spouse2} onChange={(e) => setSpouse2(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Combined filing status</label><select value={status} onChange={(e) => setStatus(e.target.value)} className={inputClass}><option>Married filing jointly</option><option>Married filing separately</option></select></div></div>
          <motion.div key={`${spouse1}-${spouse2}-${status}`} initial={{ opacity: .7, y: 4 }} animate={{ opacity: 1, y: 0 }}><div className={`bg-gradient-to-br ${result.bonus >= 0 ? "from-emerald-500 to-emerald-700" : "from-red-500 to-red-700"} rounded-2xl p-6 text-center shadow-lg`}><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.bonus >= 0 ? "Marriage Tax Bonus" : "Marriage Tax Penalty"}</p><p className="text-5xl sm:text-6xl font-black text-white" data-testid="result-marriage-tax">{money(Math.abs(result.bonus))}</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Tax filing single each</p><p className="text-lg font-extrabold text-foreground">{money(result.singleTax)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Tax filing jointly</p><p className="text-lg font-extrabold text-foreground">{money(result.jointTax)}</p></div></div></motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Your Marriage Tax Bonus or Penalty for Free</h2><p className="text-muted-foreground leading-relaxed">This marriage penalty calculator free online compares two single tax estimates with one married filing jointly tax estimate.</p><h2 className="text-2xl font-bold text-foreground">When Does Marriage Increase or Decrease Your Tax Bill</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Marriage Tax Bonus or Penalty by Income Combination</caption><thead className="bg-muted/60"><tr>{["Spouse 1 Income", "Spouse 2 Income", "Tax Filing Single Each", "Tax Filing Jointly", "Marriage Bonus/Penalty"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={`${row.a}-${row.b}`}><td className="py-2.5 px-3 font-semibold">{money(row.a)}</td><td className="py-2.5 px-3">{money(row.b)}</td><td className="py-2.5 px-3">{money(row.singleTax)}</td><td className="py-2.5 px-3">{money(row.jointTax)}</td><td className={`py-2.5 px-3 font-semibold ${row.bonus >= 0 ? "text-emerald-600 dark:text-emerald-400" : "text-red-600 dark:text-red-400"}`}>{row.bonus >= 0 ? "Bonus " : "Penalty "}{money(Math.abs(row.bonus))}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Married vs Single Tax Comparison Tool</h2><p className="text-muted-foreground leading-relaxed">Use this estimate as a planning guide. Actual taxes can change with credits, deductions, state taxes, and itemized deductions.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/marriage-tax-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


